sql:
SELECT COUNT(asset_id) AS diamond_zone_count
FROM assets
WHERE asset_type = 'Diamond Zone';

SELECT COUNT(asset_id) AS total_assets
FROM user_assets
WHERE user_id = 'specific_user_id';

SELECT COUNT(DISTINCT asset_id) AS total_unique_assets
FROM transactions
WHERE event_type = 'Transferred';

SELECT asset_name, status
FROM assets
ORDER BY asset_name ASC;

SELECT asset_id, asset_name, MAX(unit_price) AS max_unit_price
FROM assets
GROUP BY asset_id, asset_name;

external_knowledge:
- "danced through the market" refers to assets undergoing transactions;
- "passed around like hot potatoes" refers to assets being transferred;
- "top 5 performers by their unit price" means selecting the top 5 assets based on their unit price in descending order.
